import type { NextConfig } from 'next'

const nextConfig: NextConfig = {
	turbopack: {
		root: '.'
	}
}

export default nextConfig

export default function Home() {
	return (
		<main className="flex min-h-screen items-center justify-center">
			<h1 className="text-2xl font-bold">Engine Backtest Platform</h1>
		</main>
	)
}

import type { Metadata } from 'next'
import './globals.css'

export const metadata: Metadata = {
	title: 'Engine Backtest Platform',
	description: 'Charting and backtesting platform for crypto trading strategies'
}

export default function RootLayout({ children }: { children: React.ReactNode }) {
	return (
		<html lang="en" className="dark">
			<body className="bg-gray-950 text-gray-100 antialiased">{children}</body>
		</html>
	)
}

import { resolve } from 'path'
import { NextResponse } from 'next/server'
import { loadBinanceCsv } from '@/engine/csv-loader'

export async function GET() {
	const dataFile = resolve(process.cwd(), 'data/sol/binance-sol-1d-2021-to-2026-feb.csv')
	const candles = loadBinanceCsv(dataFile)

	return NextResponse.json({
		asset: 'SOL/USDT',
		timeframe: '1D',
		count: candles.length,
		candles: candles.map((c) => ({
			timestamp: c.timestamp.toISOString(),
			open: c.open,
			high: c.high,
			low: c.low,
			close: c.close,
			volume: c.volume
		}))
	})
}

import { resolve } from 'path'
